package main

import (
    "encoding/json"
    "io/ioutil"
    "net/http"
    "net/url"
    "time"
)

// Noncompliant: Direct user-provided URL
func fetchExternalData(w http.ResponseWriter, r *http.Request) {
    targetURL := r.URL.Query().Get("url")

    // Dangerous: User could provide internal URLs
    // http://localhost:8080/admin
    // http://169.254.169.254/latest/meta-data/ (AWS metadata)
    // file:///etc/passwd
    resp, err := http.Get(targetURL)
    if err != nil {
        http.Error(w, "Error fetching data", 500)
        return
    }
    defer resp.Body.Close()

    data, _ := ioutil.ReadAll(resp.Body)
    w.Write(data)
}

// Noncompliant: URL manipulation without validation
func proxyRequest(w http.ResponseWriter, r *http.Request) {
    host := r.Header.Get("X-Target-Host")
    path := r.URL.Path

    // Attacker controls the host header
    targetURL := "http://" + host + path

    client := &http.Client{}
    req, _ := http.NewRequest(r.Method, targetURL, r.Body)

    resp, err := client.Do(req)
    if err != nil {
        http.Error(w, "Proxy error", 500)
        return
    }
    defer resp.Body.Close()

    // Forward response
    for k, v := range resp.Header {
        w.Header()[k] = v
    }
    w.WriteHeader(resp.StatusCode)
    io.Copy(w, resp.Body)
}

// Noncompliant: Webhook without URL validation
func triggerWebhook(webhookURL, payload string) error {
    // User-controlled webhook URL could target internal services
    resp, err := http.Post(webhookURL, "application/json", strings.NewReader(payload))
    if err != nil {
        return err
    }
    defer resp.Body.Close()
    return nil
}

// Noncompliant: Image proxy without restrictions
func proxyImage(w http.ResponseWriter, r *http.Request) {
    imageURL := r.URL.Query().Get("image")

    // Could be used to scan internal network or access metadata
    resp, err := http.Get(imageURL)
    if err != nil {
        http.Error(w, "Image not found", 404)
        return
    }
    defer resp.Body.Close()

    w.Header().Set("Content-Type", resp.Header.Get("Content-Type"))
    io.Copy(w, resp.Body)
